using System;
using System.Linq;
using StargateGalacticCommand.Core.Models;
namespace StargateGalacticCommand.Core.Services
{
 public class FleetService{ public const int MinExplorationRangeDistance=40; public const int MaxExplorationRangeDistance=240; readonly ShipyardService _ships; public FleetService(ShipyardService ships){_ships=ships;} public int CalculateDistance(PlayerBase a,PlayerBase b){ if(a.PlanetSector.PlanetId==b.PlanetSector.PlanetId) return Math.Max(1,Math.Abs(a.PlanetSector.Number-b.PlanetSector.Number)); return 25+Math.Abs(a.PlanetSector.PlanetId-b.PlanetSector.PlanetId)*10;} public int CalculateFlightSeconds(int distance,ShipTypeDefinition d)=>Math.Max(60,(int)Math.Ceiling(distance*3600.0/d.Speed)); public int CalculateFuelCost(int distance,ShipTypeDefinition d,int count)=>Math.Max(1,distance*d.FuelPerDistance*count);
  public FleetMovement Start(PlayerBase origin,PlayerBase target,FleetMissionType mission,ShipType type,int count,ResourceStock cargo,DateTime now){ if(origin==null||target==null)throw new ArgumentNullException(); if(count<1)throw new ArgumentOutOfRangeException("count"); if(mission!=FleetMissionType.Transport&&mission!=FleetMissionType.Station)throw new InvalidOperationException("Keine Kampffunktion in Version 0.0.7."); var d=_ships.Get(type); if(!d.IsActive)throw new InvalidOperationException("Gesperrter Schiffstyp."); int load=(cargo?.Naquadah??0)+(cargo?.Trinium??0)+(cargo?.Supplies??0)+(cargo?.Energy??0)+(cargo?.Personnel??0); if(load<0)throw new ArgumentOutOfRangeException("cargo"); if(load>d.CargoCapacity*count)throw new InvalidOperationException("Ladung überschreitet Kapazität."); origin.Ships.Remove(type,count); SpendCargo(origin.Resources,cargo); int distance=CalculateDistance(origin,target); int fuel=CalculateFuelCost(distance,d,count); if(origin.Resources.Energy<fuel)throw new InvalidOperationException("Nicht genug Energie/Treibstoff."); origin.Resources.Energy-=fuel; return new FleetMovement{UserId=origin.UserId,OriginBaseId=origin.Id,OriginBase=origin,TargetBaseId=target.Id,TargetBase=target,MissionType=mission,Status=FleetMovementStatus.Outbound,ShipType=type,ShipCount=count,Naquadah=cargo?.Naquadah??0,Trinium=cargo?.Trinium??0,Supplies=cargo?.Supplies??0,Energy=cargo?.Energy??0,Personnel=cargo?.Personnel??0,StartedAtUtc=now,ArrivesAtUtc=now.AddSeconds(CalculateFlightSeconds(distance,d)),Distance=distance,FuelCost=fuel};}
  public FleetMovement StartExploration(PlayerBase origin,ShipType type,int count,int scanRangeDistance,DateTime now){ if(origin==null)throw new ArgumentNullException("origin"); if(count<1)throw new ArgumentOutOfRangeException("count"); if(scanRangeDistance<1)throw new ArgumentOutOfRangeException("scanRangeDistance"); var d=_ships.Get(type); if(!d.IsActive)throw new InvalidOperationException("Gesperrter Schiffstyp."); origin.Ships.Remove(type,count); int fuel=CalculateFuelCost(scanRangeDistance,d,count); if(origin.Resources.Energy<fuel)throw new InvalidOperationException("Nicht genug Energie/Treibstoff."); origin.Resources.Energy-=fuel; return new FleetMovement{UserId=origin.UserId,OriginBaseId=origin.Id,OriginBase=origin,TargetBaseId=origin.Id,TargetBase=origin,MissionType=FleetMissionType.Exploration,Status=FleetMovementStatus.Outbound,ShipType=type,ShipCount=count,StartedAtUtc=now,ArrivesAtUtc=now.AddSeconds(CalculateFlightSeconds(scanRangeDistance,d)),Distance=scanRangeDistance,FuelCost=fuel};}
  public FleetMovement StartRecycle(PlayerBase origin,DebrisField field,ShipType type,int count,DateTime now){ if(origin==null||field==null)throw new ArgumentNullException(); if(field.IsRecycled)throw new InvalidOperationException("Trümmerfeld ist bereits abgebaut."); if(count<1)throw new ArgumentOutOfRangeException("count"); var d=_ships.Get(type); if(!d.IsActive)throw new InvalidOperationException("Gesperrter Schiffstyp."); origin.Ships.Remove(type,count); int distance=CalculateDistance(origin,field.PlayerBase); int fuel=CalculateFuelCost(distance,d,count); if(origin.Resources.Energy<fuel)throw new InvalidOperationException("Nicht genug Energie/Treibstoff."); origin.Resources.Energy-=fuel; return new FleetMovement{UserId=origin.UserId,OriginBaseId=origin.Id,OriginBase=origin,TargetBaseId=field.PlayerBaseId,TargetBase=field.PlayerBase,DebrisFieldId=field.Id,DebrisField=field,MissionType=FleetMissionType.Recycle,Status=FleetMovementStatus.Outbound,ShipType=type,ShipCount=count,StartedAtUtc=now,ArrivesAtUtc=now.AddSeconds(CalculateFlightSeconds(distance,d)),Distance=distance,FuelCost=fuel};}
  public FleetReport Complete(FleetMovement m,DateTime now){ if(m.Status==FleetMovementStatus.Completed||m.ArrivesAtUtc>now)throw new InvalidOperationException("Flotte ist noch unterwegs."); if(m.Status==FleetMovementStatus.Outbound){ if(m.MissionType==FleetMissionType.Recycle)return CompleteRecycleArrival(m,now); AddCargo(m.TargetBase.Resources,m); if(m.MissionType==FleetMissionType.Station){m.TargetBase.Ships.Add(m.ShipType,m.ShipCount); m.Status=FleetMovementStatus.Completed; m.CompletedAtUtc=now; return R(m,"Stationierung abgeschlossen","Flotte wurde stationiert.");} m.Status=FleetMovementStatus.Returning; m.StartedAtUtc=now; m.ArrivesAtUtc=now.AddSeconds(CalculateFlightSeconds(m.Distance,_ships.Get(m.ShipType))); return R(m,"Transport angekommen","Ressourcen wurden geliefert; Flotte kehrt zurück.");} if(m.MissionType==FleetMissionType.Recycle)AddCargo(m.OriginBase.Resources,m); m.OriginBase.Ships.Add(m.ShipType,m.ShipCount); m.Status=FleetMovementStatus.Completed; m.CompletedAtUtc=now; return R(m,"Flotte zurückgekehrt",m.MissionType==FleetMissionType.Recycle?"Bergungsflotte ist mit der Beute zurück.":"Transportflotte ist zurück.");}
  FleetReport CompleteRecycleArrival(FleetMovement m,DateTime now){ var d=_ships.Get(m.ShipType); var field=m.DebrisField; if(field==null||field.IsRecycled){ m.Status=FleetMovementStatus.Returning; m.StartedAtUtc=now; m.ArrivesAtUtc=now.AddSeconds(CalculateFlightSeconds(m.Distance,d)); return R(m,"Trümmerfeld bereits abgebaut","Das Feld wurde bereits von einer anderen Flotte geborgen; die Bergungsflotte kehrt leer zurück.");} int capacity=d.CargoCapacity*m.ShipCount; int total=field.Naquadah+field.Trinium; int collect=Math.Min(total,capacity); m.Naquadah=total>0?(int)Math.Floor(collect*(field.Naquadah/(double)total)):0; m.Trinium=collect-m.Naquadah; field.Naquadah-=m.Naquadah; field.Trinium-=m.Trinium; if(field.Naquadah<=0&&field.Trinium<=0)field.IsRecycled=true; m.Status=FleetMovementStatus.Returning; m.StartedAtUtc=now; m.ArrivesAtUtc=now.AddSeconds(CalculateFlightSeconds(m.Distance,d)); return R(m,"Trümmerfeld geborgen",$"Bergungsflotte hat Naquadah {m.Naquadah} und Trinium {m.Trinium} geborgen und kehrt zur Basis zurück.");}
  void SpendCargo(ResourceStock r,ResourceStock c){ if(c==null)return; if(r.Naquadah<c.Naquadah||r.Trinium<c.Trinium||r.Supplies<c.Supplies||r.Energy<c.Energy||r.Personnel<c.Personnel)throw new InvalidOperationException("Nicht genug Ressourcen für Ladung."); r.Naquadah-=c.Naquadah; r.Trinium-=c.Trinium; r.Supplies-=c.Supplies; r.Energy-=c.Energy; r.Personnel-=c.Personnel;} void AddCargo(ResourceStock r,FleetMovement m){r.Naquadah+=m.Naquadah;r.Trinium+=m.Trinium;r.Supplies+=m.Supplies;r.Energy+=m.Energy;r.Personnel+=m.Personnel;} FleetReport R(FleetMovement m,string t,string b)=>new FleetReport{UserId=m.UserId,FleetMovement=m,CreatedAtUtc=DateTime.UtcNow,Title=t,Body=b}; }
}
